Greedy insertion with best‑fit selection per order: evaluate all non‑empty assigns via trial‑add/rollback, pick the assign giving the smallest positive cost increase, otherwise start a new empty assign as fallback.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for orderIdx := 0; orderIdx < len(oris); orderIdx++ {
		shipID := total_ship + orderIdx
		bestAssignIdx := -1
		bestCostDelta := -1.0

		for ai := 0; ai < dispatch.AssignsLen; ai++ {
			assign := &dispatch.Assigns[ai]
			oldCost := assign.Cost

			ok := assign.AddShip(shipID, oris[orderIdx], dess[orderIdx])
			if !ok {
				continue
			}
			assign.GenRoute()
			newCost := assign.Cost
			costDelta := -1.0
			if oldCost >= 0 && newCost >= 0 {
				costDelta = newCost - oldCost
			}

			assign.RemoveShip(shipID)
			assign.GenRoute()

			if ok && costDelta >= 0 && (bestAssignIdx == -1 || costDelta < bestCostDelta) {
				bestAssignIdx = ai
				bestCostDelta = costDelta
			}
		}

		if bestAssignIdx != -1 {
			target := &dispatch.Assigns[bestAssignIdx]
			target.AddShip(shipID, oris[orderIdx], dess[orderIdx])
			target.GenRoute()
		} else {
			if dispatch.AssignsLen >= MAXASSIGNS {
				continue
			}
			newAssign := &dispatch.Assigns[dispatch.AssignsLen]
			ok := newAssign.AddShip(shipID, oris[orderIdx], dess[orderIdx])
			if ok {
				newAssign.GenRoute()
				dispatch.AssignsLen++
			}
